from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["native-skills-adoption-queue-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>Native Skills Adoption Queue</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px}button,input,textarea,select{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}textarea{width:100%;min-height:90px}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>Native Skills Adoption Queue</h1><p class="muted">Phase 201: transformar candidatos nativos em fila de adoção controlada. Nada aplica código sem PR, Actions e aprovação.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/external-lab-snapshot-reader'" class="dark">Snapshot Reader</button><button onclick="dashboard()">Dashboard</button><button onclick="queue()">Fila</button></div></section><section class="panel"><h2>Promover candidato</h2><input id="candidateId" style="width:100%" placeholder="native-skill-candidate-..."/><div class="grid"><select id="priority"><option>normal</option><option>high</option><option>urgent</option><option>low</option></select><input id="project" value="GOD_MODE"/></div><textarea id="note">Promover para fila de adoção controlada; não aplicar código sem gates.</textarea><button onclick="promote()">Promover candidato</button></section><section class="panel"><h2>Promover por filtro</h2><div class="grid"><select id="domain"><option value="">todos domínios</option><option>god_mode_core</option><option>android_mobile</option><option>provider_router</option><option>cloud_deploy</option><option>verbaforge_content</option><option>github_workflow</option><option>browser_quarantine</option></select><select id="risk"><option value="">todos riscos</option><option>low_risk</option><option>medium_risk</option><option>high_risk</option></select><input id="limit" value="10"/></div><button onclick="promoteFilter()">Promover candidatos por filtro</button></section><section class="panel"><h2>Gerir item</h2><input id="itemId" style="width:100%" placeholder="adoption-queue-item-..."/><div class="grid"><select id="newStatus"><option>needs_review</option><option>approved_for_planning</option><option>planned</option><option>rejected</option><option>quarantined</option></select><input id="moduleHint" placeholder="module hint ex: provider router"/></div><textarea id="reason">Atualização via cockpit.</textarea><div class="buttons"><button onclick="updateStatus()">Atualizar estado</button><button onclick="createPlan()">Criar plano implementação</button></div></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function show(x){qs('#out').textContent=JSON.stringify(x,null,2)}async function dashboard(){show(await api('/api/native-skills-adoption-queue/dashboard'))}async function queue(){show(await api('/api/native-skills-adoption-queue/queue?limit=150'))}async function promote(){show(await api('/api/native-skills-adoption-queue/promote-candidate',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({candidate_id:qs('#candidateId').value,target_project:qs('#project').value,priority:qs('#priority').value,operator_note:qs('#note').value})}))}async function promoteFilter(){show(await api('/api/native-skills-adoption-queue/promote-candidates-by-filter',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({domain:qs('#domain').value||null,risk:qs('#risk').value||null,limit:Number(qs('#limit').value||10),target_project:qs('#project').value})}))}async function updateStatus(){show(await api('/api/native-skills-adoption-queue/update-status',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({adoption_queue_item_id:qs('#itemId').value,new_status:qs('#newStatus').value,reason:qs('#reason').value})}))}async function createPlan(){show(await api('/api/native-skills-adoption-queue/create-implementation-plan',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({adoption_queue_item_id:qs('#itemId').value,target_module_hint:qs('#moduleHint').value})}))}dashboard()</script></body></html>
"""


@router.get('/app/native-skills-adoption-queue', response_class=HTMLResponse)
async def native_skills_adoption_queue_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/native-skills-runtime', response_class=HTMLResponse)
async def native_skills_runtime_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
